const seriesA = context.panel.data.series[0];
const seriesB = context.panel.data.series[1];
const isDark = context.grafana.theme.isDark;
const textColor = isDark ? '#ccc' : '#333';
const gridBg = isDark ? 'rgba(255,255,255,0.03)' : 'rgba(0,0,0,0.02)';
const percentile = context.grafana.replaceVariables('$latencyPercentile') || 'P99';

function extractLatencyByPhase(series) {
  if (!series || !series.fields || series.fields.length < 2) return {};
  const fields = series.fields;
  let nameField = null, valueField = null;
  for (const f of fields) {
    const n = (f.name || '').toLowerCase();
    if (n.includes('quantilename') || n.includes('term')) nameField = f;
    else if (f.type === 'number' || n.includes('average') || n.includes('avg')) valueField = f;
  }
  if (!nameField || !valueField) return {};
  const result = {};
  for (let i = 0; i < nameField.values.length; i++) {
    result[nameField.values[i]] = valueField.values[i] || 0;
  }
  return result;
}

const latA = extractLatencyByPhase(seriesA);
const latB = extractLatencyByPhase(seriesB);
const allPhases = [...new Set([...Object.keys(latA), ...Object.keys(latB)])].sort();

if (allPhases.length === 0) {
  return { title: { text: 'No VMI latency data', left: 'center', top: 'center', textStyle: { color: textColor, fontSize: 16 } } };
}

const valsA = allPhases.map(p => (latA[p] || 0) / 1000);
const valsB = allPhases.map(p => (latB[p] || 0) / 1000);

return {
  tooltip: { trigger: 'axis', axisPointer: { type: 'shadow' },
    formatter: function(params) {
      let s = '<b>' + params[0].name + '</b><br/>';
      params.forEach(p => { s += p.marker + ' ' + p.seriesName + ': ' + (p.value || 0).toFixed(1) + ' s<br/>'; });
      const a = params[0] ? params[0].value : 0;
      const b = params[1] ? params[1].value : 0;
      if (a > 0 && b > 0) {
        const pct = ((b - a) / a * 100).toFixed(1);
        const arrow = b > a ? '\u25B2' : b < a ? '\u25BC' : '=';
        const color = b > a ? '#F2495C' : b < a ? '#73BF69' : textColor;
        s += '<span style="color:' + color + '">' + arrow + ' ' + pct + '%</span>';
      }
      return s;
    }
  },
  legend: { data: ['Run A', 'Run B'], textStyle: { color: textColor } },
  grid: { left: 60, right: 30, top: 40, bottom: 60, backgroundColor: gridBg, show: true },
  xAxis: { type: 'category', data: allPhases, axisLabel: { color: textColor, rotate: 30, fontSize: 11 } },
  yAxis: { type: 'value', name: percentile + ' Latency (s)', nameTextStyle: { color: textColor }, axisLabel: { color: textColor }, splitLine: { lineStyle: { color: isDark ? 'rgba(255,255,255,0.1)' : 'rgba(0,0,0,0.1)' } } },
  series: [
    { name: 'Run A', type: 'bar', data: valsA, itemStyle: { color: '#5794F2' }, barGap: '10%', barCategoryGap: '30%' },
    { name: 'Run B', type: 'bar', data: valsB, itemStyle: { color: '#FF9830' } }
  ]
};

const sA = context.panel.data.series[0];
const sB = context.panel.data.series[1];
const isDark = context.grafana.theme.isDark;
const textColor = isDark ? '#E0E0E0' : '#1a1a1a';
const headerBg = isDark ? 'rgba(255,255,255,0.06)' : 'rgba(0,0,0,0.04)';
const rowHoverBg = isDark ? 'rgba(255,255,255,0.04)' : 'rgba(0,0,0,0.02)';

const HIGHER_IS_WORSE = ['nodeCPU','kubevirtCPU','containerCPU-Prometheus','kubevirtAPIRequestRate','APIRequestRate','kubevirtWorkQueueDepth','kubevirtWorkQueueAddRate','99thEtcdDiskWalFsyncDurationSeconds','99thEtcdDiskBackendCommitDurationSeconds','nodeDiskWrittenBytes','nodeDiskReadBytes','rxNetworkBytes','txNetworkBytes'];
const HIGHER_IS_BETTER = ['nodeMemoryAvailable'];

function parseTermsStats(series) {
  const result = {};
  if (!series || !series.fields) return result;
  const fields = series.fields;
  let nameField = null, avgField = null, minField = null, maxField = null, countField = null;
  for (const f of fields) {
    const n = (f.name || '').toLowerCase();
    if (n === 'metricname.keyword' || n.includes('term')) nameField = f;
    else if (n.includes('average') || n.includes('avg')) avgField = f;
    else if (n === 'min' || n === 'min value') minField = f;
    else if (n === 'max' || n === 'max value') maxField = f;
    else if (n.includes('count')) countField = f;
  }
  if (!nameField) return result;
  for (let i = 0; i < nameField.values.length; i++) {
    const name = nameField.values[i];
    const avg = avgField ? avgField.values[i] : 0;
    const mn = minField ? minField.values[i] : 0;
    const mx = maxField ? maxField.values[i] : 0;
    const cnt = countField ? countField.values[i] : 0;
    const range = mx - mn;
    const approxStd = range / 4;
    result[name] = { avg: avg, std: approxStd, min: mn, max: mx, count: cnt };
  }
  return result;
}

const statsA = parseTermsStats(sA);
const statsB = parseTermsStats(sB);
const allMetrics = [...new Set([...Object.keys(statsA), ...Object.keys(statsB)])].filter(m => m !== 'metadata' && m !== 'vmiLatencyQuantilesMeasurement' && m !== 'vmiLatencyMeasurement' && m !== 'pvcLatencyQuantilesMeasurement' && m !== 'pvcLatencyMeasurement' && m !== 'jobSummary' && m !== 'alerts' && m !== 'validation' && m !== 'clusterVersion' && m !== 'kubevirtVersion' && m !== 'etcdVersion' && m !== 'nodeRoles' && m !== 'nodeStatus' && m !== 'etcdServerIsLeader').sort();

function fmt(v) {
  if (v === null || v === undefined || isNaN(v)) return '-';
  if (Math.abs(v) >= 1e9) return (v / 1e9).toFixed(2) + 'G';
  if (Math.abs(v) >= 1e6) return (v / 1e6).toFixed(2) + 'M';
  if (Math.abs(v) >= 1e3) return (v / 1e3).toFixed(2) + 'K';
  return v.toFixed(2);
}

function getColor(metric, pctChange) {
  const isWorse = HIGHER_IS_WORSE.includes(metric);
  const isBetter = HIGHER_IS_BETTER.includes(metric);
  const absPct = Math.abs(pctChange);
  if (absPct < 5) return isDark ? '#73BF69' : '#37872D';
  if (absPct < 15) return isDark ? '#FADE2A' : '#E0B400';
  if (isWorse && pctChange > 0) return isDark ? '#F2495C' : '#C4162A';
  if (isWorse && pctChange < 0) return isDark ? '#73BF69' : '#37872D';
  if (isBetter && pctChange < 0) return isDark ? '#F2495C' : '#C4162A';
  if (isBetter && pctChange > 0) return isDark ? '#73BF69' : '#37872D';
  return absPct >= 15 ? (isDark ? '#FADE2A' : '#E0B400') : textColor;
}

const colWidths = [220, 100, 100, 90, 80, 90, 90, 50];
const headers = ['Metric', 'Run A Mean', 'Run B Mean', 'Delta', '% Change', 'StdDev A', 'StdDev B', 'Trend'];
const rowH = 28;
const headerH = 36;
const topPad = 10;
const leftPad = 10;

const elements = [];
let totalW = colWidths.reduce((a, b) => a + b, 0) + leftPad * 2;

headers.forEach((h, ci) => {
  let x = leftPad;
  for (let j = 0; j < ci; j++) x += colWidths[j];
  elements.push({
    type: 'text', left: x, top: topPad, style: {
      text: h, fontSize: 13, fontWeight: 'bold', fill: textColor, width: colWidths[ci], height: headerH, textAlign: ci === 0 ? 'left' : 'right'
    }
  });
});

elements.push({
  type: 'rect', left: leftPad, top: topPad + headerH - 2, shape: { width: totalW - leftPad * 2, height: 1 },
  style: { fill: isDark ? 'rgba(255,255,255,0.2)' : 'rgba(0,0,0,0.15)' }
});

allMetrics.forEach((metric, ri) => {
  const a = statsA[metric] || { avg: 0, std: 0 };
  const b = statsB[metric] || { avg: 0, std: 0 };
  const delta = b.avg - a.avg;
  const pctChange = a.avg !== 0 ? (delta / a.avg) * 100 : (b.avg !== 0 ? 100 : 0);
  const color = getColor(metric, pctChange);
  const arrow = pctChange > 2 ? '\u25B2' : pctChange < -2 ? '\u25BC' : '\u2015';
  const rowY = topPad + headerH + 6 + ri * rowH;
  const vals = [metric, fmt(a.avg), fmt(b.avg), fmt(delta), pctChange.toFixed(1) + '%', fmt(a.std), fmt(b.std), arrow];

  if (ri % 2 === 0) {
    elements.push({
      type: 'rect', left: leftPad, top: rowY - 2, shape: { width: totalW - leftPad * 2, height: rowH },
      style: { fill: rowHoverBg }
    });
  }

  vals.forEach((v, ci) => {
    let x = leftPad;
    for (let j = 0; j < ci; j++) x += colWidths[j];
    const isColorCol = ci === 4 || ci === 7;
    elements.push({
      type: 'text', left: x, top: rowY, style: {
        text: String(v), fontSize: 12, fill: isColorCol ? color : textColor,
        fontWeight: isColorCol ? 'bold' : 'normal',
        width: colWidths[ci], height: rowH, textAlign: ci === 0 ? 'left' : 'right'
      }
    });
  });
});

return { graphic: { elements: elements } };

const sA = context.panel.data.series[0];
const sB = context.panel.data.series[1];
const isDark = context.grafana.theme.isDark;
const textColor = isDark ? '#ccc' : '#333';

function extractTimeSeries(series) {
  if (!series || !series.fields || series.fields.length < 2) return { times: [], values: [] };
  const timeField = series.fields.find(f => f.type === 'time') || series.fields[0];
  const valueField = series.fields.find(f => f.type === 'number' && f.name !== 'Time') || series.fields[1];
  return { times: Array.from(timeField.values), values: Array.from(valueField.values) };
}

const a = extractTimeSeries(sA);
const b = extractTimeSeries(sB);

if (a.times.length === 0 && b.times.length === 0) {
  return { title: { text: 'No data', left: 'center', top: 'center', textStyle: { color: textColor, fontSize: 16 } } };
}

const startA = a.times.length > 0 ? a.times[0] : 0;
const startB = b.times.length > 0 ? b.times[0] : 0;

const dataA = a.times.map((t, i) => [(t - startA) / 60000, a.values[i]]).filter(d => d[1] != null);
const dataB = b.times.map((t, i) => [(t - startB) / 60000, b.values[i]]).filter(d => d[1] != null);

function calcStats(data) {
  if (data.length === 0) return { mean: 0, max: 0, min: 0 };
  const vals = data.map(d => d[1]);
  const mean = vals.reduce((s, v) => s + v, 0) / vals.length;
  return { mean, max: Math.max(...vals), min: Math.min(...vals) };
}

const stA = calcStats(dataA);
const stB = calcStats(dataB);
const pctChange = stA.mean !== 0 ? ((stB.mean - stA.mean) / stA.mean * 100).toFixed(1) : '0.0';
const arrow = Number(pctChange) > 2 ? '▲' : Number(pctChange) < -2 ? '▼' : '≈';
const changeColor = Number(pctChange) > 5 ? '#F2495C' : Number(pctChange) < -5 ? '#73BF69' : textColor;

return {
  title: {
    text: '{main|' + (context.grafana.replaceVariables('${metricToCompare}') || 'Metric') + '}  {change|' + arrow + ' ' + pctChange + '%}',
    left: 'center', top: 5,
    textStyle: {
      rich: {
        main: { fontSize: 15, fontWeight: 'bold', color: textColor },
        change: { fontSize: 14, fontWeight: 'bold', color: changeColor, padding: [0, 0, 0, 12] }
      }
    }
  },
  tooltip: {
    trigger: 'axis',
    formatter: function(params) {
      let s = 'Elapsed: ' + (params[0] ? params[0].value[0].toFixed(1) : '?') + ' min<br/>';
      params.forEach(p => { s += p.marker + ' ' + p.seriesName + ': ' + (p.value[1] != null ? p.value[1].toFixed(4) : '-') + '<br/>'; });
      return s;
    }
  },
  legend: {
    data: [
      'Run A (mean: ' + stA.mean.toFixed(2) + ')',
      'Run B (mean: ' + stB.mean.toFixed(2) + ')'
    ],
    bottom: 5, textStyle: { color: textColor, fontSize: 11 }
  },
  grid: { left: 70, right: 30, top: 45, bottom: 55, backgroundColor: isDark ? 'rgba(255,255,255,0.02)' : 'rgba(0,0,0,0.01)', show: true },
  xAxis: { type: 'value', name: 'Elapsed (min)', nameTextStyle: { color: textColor }, axisLabel: { color: textColor }, splitLine: { lineStyle: { color: isDark ? 'rgba(255,255,255,0.05)' : 'rgba(0,0,0,0.06)' } } },
  yAxis: { type: 'value', axisLabel: { color: textColor }, splitLine: { lineStyle: { color: isDark ? 'rgba(255,255,255,0.08)' : 'rgba(0,0,0,0.08)' } } },
  series: [
    {
      name: 'Run A (mean: ' + stA.mean.toFixed(2) + ')',
      type: 'line', data: dataA, smooth: 0.3,
      lineStyle: { width: 2, color: '#5794F2' },
      itemStyle: { color: '#5794F2' }, symbol: 'none',
      areaStyle: { color: { type: 'linear', x: 0, y: 0, x2: 0, y2: 1, colorStops: [{ offset: 0, color: 'rgba(87,148,242,0.15)' }, { offset: 1, color: 'rgba(87,148,242,0.01)' }] } },
      markLine: { silent: true, data: [{ type: 'average', name: 'Avg A' }], lineStyle: { color: '#5794F2', type: 'dashed', width: 1 }, label: { show: false } }
    },
    {
      name: 'Run B (mean: ' + stB.mean.toFixed(2) + ')',
      type: 'line', data: dataB, smooth: 0.3,
      lineStyle: { width: 2, color: '#FF9830', type: 'dashed' },
      itemStyle: { color: '#FF9830' }, symbol: 'none',
      areaStyle: { color: { type: 'linear', x: 0, y: 0, x2: 0, y2: 1, colorStops: [{ offset: 0, color: 'rgba(255,152,48,0.12)' }, { offset: 1, color: 'rgba(255,152,48,0.01)' }] } },
      markLine: { silent: true, data: [{ type: 'average', name: 'Avg B' }], lineStyle: { color: '#FF9830', type: 'dashed', width: 1 }, label: { show: false } }
    }
  ],
  dataZoom: [{ type: 'inside', xAxisIndex: 0 }]
};

const series = context.panel.data.series;
const isDark = context.grafana.theme.isDark;
const textColor = isDark ? '#ccc' : '#333';
const uuidA = context.grafana.replaceVariables('$uuidA');
const uuidB = context.grafana.replaceVariables('$uuidB');

const runPoints = [];
if (series && series.length > 0) {
  for (const s of series) {
    if (!s.fields || s.fields.length < 2) continue;
    const timeF = s.fields.find(f => f.type === 'time') || s.fields[0];
    const valF = s.fields.find(f => f.type === 'number') || s.fields[1];
    for (let i = 0; i < timeF.values.length; i++) {
      if (valF.values[i] != null) {
        runPoints.push({ ts: timeF.values[i], val: valF.values[i] });
      }
    }
  }
}

runPoints.sort((a, b) => a.ts - b.ts);

const scatterData = runPoints.map(p => [p.ts, p.val]);

let maData = [];
const windowSize = Math.max(3, Math.floor(runPoints.length / 5));
for (let i = 0; i < runPoints.length; i++) {
  const start = Math.max(0, i - Math.floor(windowSize / 2));
  const end = Math.min(runPoints.length, start + windowSize);
  const slice = runPoints.slice(start, end);
  const avg = slice.reduce((s, p) => s + p.val, 0) / slice.length;
  maData.push([runPoints[i].ts, avg]);
}

return {
  title: { text: 'Historical Trend — Duration by Run', left: 'center', top: 5, textStyle: { color: textColor, fontSize: 14 } },
  tooltip: {
    trigger: 'item',
    formatter: function(p) {
      const d = new Date(p.value[0]);
      return d.toLocaleDateString() + '<br/>Duration: ' + p.value[1].toFixed(0) + 's';
    }
  },
  grid: { left: 70, right: 30, top: 45, bottom: 40, backgroundColor: isDark ? 'rgba(255,255,255,0.02)' : 'rgba(0,0,0,0.01)', show: true },
  xAxis: { type: 'time', axisLabel: { color: textColor }, splitLine: { show: false } },
  yAxis: { type: 'value', name: 'Duration (s)', nameTextStyle: { color: textColor }, axisLabel: { color: textColor }, splitLine: { lineStyle: { color: isDark ? 'rgba(255,255,255,0.08)' : 'rgba(0,0,0,0.08)' } } },
  series: [
    {
      name: 'Runs', type: 'scatter', data: scatterData,
      symbolSize: 10, itemStyle: { color: '#8AB8FF', opacity: 0.7 }
    },
    {
      name: 'Trend', type: 'line', data: maData, smooth: 0.4,
      lineStyle: { color: '#FF6E76', width: 2, type: 'dashed' },
      symbol: 'none', itemStyle: { color: '#FF6E76' }
    }
  ],
  legend: { data: ['Runs', 'Trend'], bottom: 5, textStyle: { color: textColor } }
};
